script:
set +e
echo === find bot_framework_auth ===
sudo find /home /opt /usr/local -maxdepth 5 -name 'bot_framework_auth*' 2>/dev/null
echo === other bot imports ===
for s in heather afrah jose axel lia david cameron; do echo "--- $s"; sudo grep -h 'bot_framework_auth' /home/$s/${s}-bot.py 2>/dev/null | head -3; done
echo === try linking ===
if [ -f /home/azureuser/bot_framework_auth.py ]; then sudo -u alejandro ln -sfn /home/azureuser/bot_framework_auth.py /home/alejandro/bot_framework_auth.py && echo linked; fi
sudo systemctl restart alejandro-bot.service
sleep 5
echo === after restart ===
echo "bot=$(systemctl is-active alejandro-bot.service)"
sudo journalctl -u alejandro-bot.service -n 5 --no-pager | tail -5
